class Solution:
    def largestPalindrome(self, n: int) -> int:
        if n == 1: return 9
        lo, hi = 10**(n-1), 10**n - 1
        for a in range(hi, lo - 1, -1):
            s = str(a)
            p = int(s + s[::-1])
            b = p // a
            if b <= hi and p % a == 0:
                return p % 1337
        return 0

